# PowerShell: Bulk-add users to an AU from a CSV file
# CSV columns: userPrincipalName

param(
    [string]$AuDisplayName = "West Region",
    [string]$CsvPath = "C:\au-members.csv"
)

Connect-MgGraph -Scopes "AdministrativeUnit.ReadWrite.All", "User.Read.All"

# Resolve AU object ID
$au = Get-MgDirectoryAdministrativeUnit -Filter "displayName eq '$AuDisplayName'" |
      Select-Object -First 1
if (-not $au) { throw "AU '$AuDisplayName' not found" }

$users = Import-Csv $CsvPath
$added = 0; $failed = 0

foreach ($row in $users) {
    try {
        $user = Get-MgUser -Filter "userPrincipalName eq '$($row.userPrincipalName)'" `
                           -ErrorAction Stop
        New-MgDirectoryAdministrativeUnitMemberByRef `
            -AdministrativeUnitId $au.Id `
            -BodyParameter @{
                "@odata.id" = "https://graph.microsoft.com/v1.0/users/$($user.Id)"
            }
        $added++
    }
    catch {
        Write-Warning "Failed $($row.userPrincipalName): $_"
        $failed++
    }
}
Write-Output "Added: $added  Failed: $failed"
Disconnect-MgGraph

# Terraform: Manage Administrative Units as code
# Requires: azuread provider >= 2.36.0

terraform {
  required_providers {
    azuread = {
      source  = "hashicorp/azuread"
      version = "~> 2.50"
    }
  }
}

# Assigned AU for West Region
resource "azuread_administrative_unit" "west_region" {
  display_name              = "West Region"
  description               = "Users and devices in the western sales territory"
  hidden_membership_enabled = false   # true = restricted AU
}

# Dynamic AU for Corporate Devices
resource "azuread_administrative_unit" "corporate_devices" {
  display_name = "Corporate Devices"
  description  = "All Intune-enrolled, corporate-owned Windows devices"

  # Dynamic membership — requires AAD P1
  dynamic_membership {
    enabled = true
    rule    = "(device.deviceOwnership -eq \"Company\") and (device.operatingSystem -eq \"Windows\")"
  }
}

# Add a user to the assigned AU
resource "azuread_administrative_unit_member" "alice_west" {
  administrative_unit_object_id = azuread_administrative_unit.west_region.id
  member_object_id              = azuread_user.alice.object_id
}

# Scoped role assignment — User Administrator scoped to West Region AU
data "azuread_directory_role_template" "user_administrator" {
  display_name = "User Administrator"
}

resource "azuread_directory_role" "user_administrator" {
  template_id = data.azuread_directory_role_template.user_administrator.template_id
}

resource "azuread_directory_role_assignment" "helpdesk_scoped" {
  role_id             = azuread_directory_role.user_administrator.template_id
  principal_object_id = azuread_user.helpdesk_admin.object_id
  # Scope to the AU
  directory_scope_id = "/administrativeUnits/${azuread_administrative_unit.west_region.id}"
}

# Decision helper: should I use an AU or a group for this scenario?

scenarios = [
    {
        "requirement": "Restrict who can manage (reset password for) Sales department users",
        "use": "Administrative Unit",
        "reason": "Role scoping — AU limits the blast radius of delegated admin roles",
    },
    {
        "requirement": "Grant Sales users access to a SharePoint site",
        "use": "Security Group",
        "reason": "Resource access is controlled by group membership, not AUs",
    },
    {
        "requirement": "Apply a Conditional Access policy only to Finance employees",
        "use": "Security Group (as CA target)",
        "reason": "CA policies target users/groups/roles, not AUs directly",
    },
    {
        "requirement": "Enable Microsoft Authenticator only for IT department pilot",
        "use": "Administrative Unit",
        "reason": "Auth method policies support AU targeting for phased rollouts",
    },
    {
        "requirement": "Assign Microsoft 365 E3 licenses to HR employees",
        "use": "Security Group (group-based licensing)",
        "reason": "License assignment uses groups, not AUs",
    },
    {
        "requirement": "Ensure helpdesk in Germany can only manage German user accounts",
        "use": "Administrative Unit",
        "reason": "This is scoped delegation — the helpdesk role is constrained to the Germany AU",
    },
]

print(f"{'Requirement':<55} {'Use':<30} {'Reason'}")
print("-" * 120)
for s in scenarios:
    print(f"{s['requirement']:<55} {s['use']:<30} {s['reason']}")
